{
    "$schema": "http://json-schema.org/draft-04/schema",
    "additionalProperties": false,
    "description": "ElevationLayer is a tile layer used for rendering elevation in web scenes.",
    "esriDocumentation": {
        "examples": [
            {
                "code": {
                    "baseMap": {
                        "baseMapLayers": [],
                        "elevationLayers": [
                            {
                                "id": "globalElevation",
                                "layerType": "ArcGISTiledElevationServiceLayer",
                                "title": "Terrain3D",
                                "url": "http://elevation3d.arcgis.com/arcgis/rest/services/WorldElevation3D/Terrain3D/ImageServer",
                                "visibility": true
                            }
                        ],
                        "title": "elevation-only basemap"
                    }
                },
                "description": "Live sample web scene showing [elevationLayers](https://www.arcgis.com/home/webscene/viewer.html?webscene=a06aa4a2e4264b789686e66a75d863ca)",
                "schema": "baseMap_schema.json",
                "title": "elevationLayer"
            }
        ]
    },
    "properties": {
        "id": {
            "description": "A unique identifying string for the layer",
            "type": "string"
        },
        "itemId": {
            "description": "Optional string containing the item ID of the service if it's registered on ArcGIS Online or your organization's portal.",
            "type": "string"
        },
        "layerType": {
            "description": "String indicating the layer type",
            "enum": [
                "ArcGISTiledElevationServiceLayer"
            ],
            "type": "string"
        },
        "listMode": {
            "description": "To show or hide the elevation layer in the layer list",
            "enum": [
                "show",
                "hide"
            ],
            "type": "string"
        },
        "title": {
            "description": "A user-friendly string title for the layer that can be used in a table of contents. If this is not included, a title is derived from the service.",
            "type": "string"
        },
        "url": {
            "_format": "uri",
            "description": "The URL to the layer.If the layer is not from a web service but rather a feature collection, then the url property is omitted",
            "type": "string"
        },
        "visibility": {
            "default": true,
            "description": "Boolean property determining whether the layer is initially visible in the web scene.",
            "type": "boolean"
        }
    },
    "required": [
        "id",
        "layerType",
        "title",
        "url"
    ],
    "title": "elevationLayer",
    "type": "object"
}

{
    "title": "Raster Data Elevation Layer",
    "type": "object",
    "$schema": "http://json-schema.org/draft-04/schema",
    "description": "RasterDataElevationLayer is a single-band raster layer used for rendering elevation.",
    "properties": {
        "id": {
            "type": "string",
            "description": "A unique identifying string for the layer"
        },
        "layerType": {
            "type": "string",
            "description": "String indicating the layer type",
            "enum": [
                "RasterDataElevationLayer"
            ]
        },
        "listMode": {
            "type": "string",
            "description": "To show or hide the elevation layer in the layer list",
            "enum": [
                "hide",
                "show"
            ]
        },
        "path": {
            "type": "string",
            "description": "For offline data, a path to an ArcGIS Runtime supported raster data file. A URI format is used, starting with file: followed by a file system path. A relative path must be from the file which defines the layer. For example `file:../commondata/raster_data/beijing.tif`",
            "pattern": "^file:.+$"
        },
        "title": {
            "type": "string",
            "description": "A user-friendly string title for the layer that can be used in a table of contents. If this is not included, a title is derived from the service."
        },
        "visibility": {
            "type": "boolean",
            "description": "Boolean property determining whether the layer is initially visible in the web scene.",
            "default": true
        }
    },
    "required": [
        "id",
        "layerType",
        "path",
        "title"
    ],
    "additionalProperties": false,
    "esriDocumentation": {
        "examples": [
            {
                "title": "Raster Data Elevation Layer",
                "schema": "ground_schema.json",
                "code": {
                    "ground": {
                        "layers": [
                            {
                                "id": "local_dem",
                                "title": "Local DEM",
                                "path": "file:../commondata/DEM.tif",
                                "visibility": true,
                                "layerType": "RasterDataElevationLayer"
                            }
                        ]
                    }
                }
            }
        ]
    }
}

{
    "$schema": "http://json-schema.org/draft-04/schema",
    "additionalProperties": false,
    "anyOf": [
        {
            "required": [
                "id",
                "layerType",
                "title",
                "url"
            ]
        },
        {
            "required": [
                "id",
                "layerType",
                "path",
                "title"
            ]
        }
    ],
    "description": "Tiled Elevation Layer is a tile layer used for rendering elevation.",
    "esriDocumentation": {
        "examples": [
            {
                "code": {
                    "ground": {
                        "layers": [
                            {
                                "id": "globalElevation",
                                "layerType": "ArcGISTiledElevationServiceLayer",
                                "title": "Terrain3D",
                                "url": "http://elevation3d.arcgis.com/arcgis/rest/services/WorldElevation3D/Terrain3D/ImageServer",
                                "visibility": true
                            }
                        ]
                    }
                },
                "description": "Live sample web scene showing [elevationLayers](https://www.arcgis.com/home/webscene/viewer.html?webscene=a06aa4a2e4264b789686e66a75d863ca)",
                "schema": "ground_schema.json",
                "title": "Tiled Elevation Layer"
            }
        ]
    },
    "properties": {
        "id": {
            "description": "A unique identifying string for the layer",
            "type": "string"
        },
        "itemId": {
            "description": "Optional string containing the item ID of the service if it's registered on ArcGIS Online or your organization's portal.",
            "type": "string"
        },
        "layerType": {
            "description": "String indicating the layer type",
            "enum": [
                "ArcGISTiledElevationServiceLayer"
            ],
            "type": "string"
        },
        "listMode": {
            "description": "To show or hide the elevation layer in the layer list",
            "enum": [
                "hide",
                "show"
            ],
            "type": "string"
        },
        "path": {
            "description": "For offline data, a path to a tile package containing elevation data. A URI format is used, starting with `file:` followed by a file system path with an extension of `.tpk` or `.tpkx`. A relative path must be from the file which defines the layer. For example `file:../p20/portland.tpk`.",
            "pattern": "^file:.+\\.tpkx?$",
            "type": "string"
        },
        "title": {
            "description": "A user-friendly string title for the layer that can be used in a table of contents. If this is not included, a title is derived from the service.",
            "type": "string"
        },
        "url": {
            "_format": "uri",
            "description": "The URL to the layer.If the layer is not from a web service but rather a feature collection, then the url property is omitted",
            "type": "string"
        },
        "visibility": {
            "default": true,
            "description": "Boolean property determining whether the layer is initially visible in the web scene.",
            "type": "boolean"
        }
    },
    "title": "Tiled Elevation Layer",
    "type": "object"
}

{
    "title": "Web Map Tile Service Info",
    "type": "object",
    "$schema": "http://json-schema.org/draft-04/schema",
    "description": "Object defines and provides information about layers in a [WMTSLayer](webTiledLayer.md) service.",
    "properties": {
        "customLayerParameters": {
            "type": "object",
            "description": "A sequence of parameters used to append different custom parameters to a WMTS tile request. These parameters are applied to `GetTile`. The `customLayerParameters` property takes precedence if `customParameters` is also present.",
            "patternProperties": {
                ".*": {
                    "type": "string"
                }
            }
        },
        "customParameters": {
            "type": "object",
            "description": "A sequence of parameters used to append custom parameters to all WMTS requests. These parameters are applied to `GetCapabilities` and `GetTile`. If used with the `customLayerParameters` property, `customParameters` will not take precedence.",
            "patternProperties": {
                ".*": {
                    "type": "string"
                }
            }
        },
        "layerIdentifier": {
            "type": "string",
            "description": "Identifier for the specific layer used in the WMTS service. Required input by the user."
        },
        "tileMatrixSet": {
            "type": "string",
            "description": "Tiling schema, set by the WMTS service."
        },
        "url": {
            "type": "string",
            "description": "URL to the WMTS web service. Required input by the user.",
            "format": "uri"
        }
    },
    "additionalProperties": false,
    "esriDocumentation": {
        "examples": [
            {
                "title": "Web Map Service Tile Info",
                "description": "The WMTSInfo as used within a WMTS Layer",
                "schema": "wmtsInfo_schema.json",
                "code": {
                    "wmtsInfo": {
                        "url": "http://maps.wien.gv.at/wmts",
                        "layerIdentifier": "lb",
                        "tileMatrixSet": "google3857",
                        "customParameters": {
                            "token": "1ADE-FR54T"
                        },
                        "customLayerParameters": {
                            "style": "basic"
                        }
                    }
                }
            }
        ]
    }
}

{
    "$schema": "http://json-schema.org/draft-06/schema#",
    "title": "Ansible Inventory",
    "description": "Ansible Inventory for the script inventory plugin",
    "type": "object",
    "patternProperties": {
        "^\\w$": {
            "type": "object",
            "properties": {
                "hosts": {
                    "description": "list of hosts that are part of this group",
                    "type": "array",
                    "items": {
                        "type": "string"
                    }
                },
                "vars": {
                    "type": "object",
                    "description": "Variables to assign to hosts that are part of this group",
                    "patternProperties": {
                        "^\\w$": {
                            "type": "object",
                            "description": "Vars for this hosts in this group"
                        }
                    }
                },
                "children": {
                    "description": "list of groups that are children of this group, their hosts will be added to this group",
                    "type": "array",
                    "items": {
                        "type": "string"
                    }
                }
            },
            "additionalProperties": false
        },
        "_meta": {
            "type": "object",
            "description": "Key that avoids calling the script per host",
            "required": [
                "hostvars"
            ],
            "properties": {
                "hostvars": {
                    "type": "object",
                    "description": "Each key is a hostname and the value is a dictionary of the variables for that host",
                    "patternProperties": {
                        "^\\w$": {
                            "type": "object",
                            "description": "Hosts with their associated vars",
                            "patternProperties": {
                                "^\\w$": {
                                    "type": "object",
                                    "description": "Vars for this host"
                                }
                            }
                        }
                    }
                }
            },
            "additionalProperties": false
        }
    },
    "additionalProperties": false
}

{
    "properties": {
