                    "type": "number"
                },
                "mem": {
                    "default": 128.0,
                    "description": "Memory to allocate to each service instance.",
                    "minimum": 128.0,
                    "type": "number"
                },
                "name": {
                    "default": "cadvisor",
                    "description": "Name of this service instance",
                    "type": "string"
                }
            },
            "type": "object"
        }
    }
}

